import { useState, useMemo, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useQuery } from "@tanstack/react-query";
import { Check, ChevronsUpDown, MapPin, Search, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { ScrollArea } from "@/components/ui/scroll-area";
import { supabase } from "@/integrations/supabase/client";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { cn } from "@/lib/utils";

interface RestaurantOption {
  id: string;
  name: string;
  name_en?: string | null;
  name_pt?: string | null;
  city?: string | null;
}

interface Props {
  /** Currently selected restaurant id ("" or "__none__" = none). */
  value: string;
  onChange: (id: string) => void;
  /** When true, fetch ALL restaurants (admin). Otherwise use `restaurants` prop. */
  loadAll?: boolean;
  /** Pre-loaded restaurant list (for non-admin users). */
  restaurants?: RestaurantOption[];
  /** When true, "no restaurant" option is hidden (required mode). */
  required?: boolean;
  label?: string;
  className?: string;
}

const SEARCH_THRESHOLD = 6;
const MAX_RESULTS = 50;

const RestaurantPicker = ({
  value,
  onChange,
  loadAll = false,
  restaurants: externalList,
  required = false,
  label,
  className,
}: Props) => {
  const { t } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");

  // Admin: lazy load all restaurants only when popover opens
  const { data: allRestaurants = [], isLoading } = useQuery({
    queryKey: ["all-restaurants-picker"],
    queryFn: async () => {
      const { data, error } = await (supabase as any)
        .from("restaurants")
        .select("id, name, name_en, name_pt, city")
        .eq("visible", true)
        .order("name", { ascending: true })
        .limit(5000);
      if (error) throw error;
      return (data || []) as RestaurantOption[];
    },
    enabled: loadAll && open,
    staleTime: 5 * 60_000,
  });

  const list: RestaurantOption[] = loadAll ? allRestaurants : externalList || [];

  const showSearch = list.length > SEARCH_THRESHOLD;

  const filtered = useMemo(() => {
    if (!query.trim()) return list.slice(0, MAX_RESULTS);
    const q = query.trim().toLowerCase();
    const out: RestaurantOption[] = [];
    for (const r of list) {
      const hay = [
        r.name,
        r.name_en,
        r.name_pt,
        r.city,
      ].filter(Boolean).join(" ").toLowerCase();
      if (hay.includes(q)) out.push(r);
      if (out.length >= MAX_RESULTS) break;
    }
    return out;
  }, [list, query]);

  const selected = useMemo(
    () => list.find((r) => r.id === value),
    [list, value]
  );

  // Reset query on close
  useEffect(() => {
    if (!open) setQuery("");
  }, [open]);

  const displayLabel = selected
    ? getLocalizedField(selected, "name")
    : value === "__none__" || !value
    ? t("community.noRestaurant", "不关联餐厅")
    : t("community.selectRestaurant", "选择餐厅");

  return (
    <div className={cn("space-y-2", className)}>
      {label && (
        <Label>
          <MapPin className="h-4 w-4 inline mr-1" />
          {label} {required ? "*" : ""}
        </Label>
      )}
      <Popover open={open} onOpenChange={setOpen}>
        <PopoverTrigger asChild>
          <Button
            type="button"
            variant="outline"
            role="combobox"
            aria-expanded={open}
            className="w-full justify-between font-normal"
          >
            <span className="flex items-center gap-2 min-w-0">
              <MapPin className="h-4 w-4 text-muted-foreground shrink-0" />
              <span className="truncate">{displayLabel}</span>
            </span>
            <ChevronsUpDown className="h-4 w-4 opacity-50 shrink-0" />
          </Button>
        </PopoverTrigger>
        <PopoverContent
          className="p-0 w-[--radix-popover-trigger-width] max-w-[420px]"
          align="start"
        >
          {showSearch && (
            <div className="p-2 border-b">
              <div className="relative">
                <Search className="absolute left-2 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  autoFocus
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder={t("community.searchRestaurant", "搜索餐厅...")}
                  className="pl-8 pr-8 h-9"
                />
                {query && (
                  <button
                    type="button"
                    onClick={() => setQuery("")}
                    className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                  >
                    <X className="h-3.5 w-3.5" />
                  </button>
                )}
              </div>
            </div>
          )}
          <ScrollArea className="max-h-72">
            <div className="p-1">
              {!required && (
                <button
                  type="button"
                  onClick={() => {
                    onChange("__none__");
                    setOpen(false);
                  }}
                  className={cn(
                    "w-full text-left px-2 py-2 rounded-sm text-sm hover:bg-accent flex items-center gap-2",
                    (!value || value === "__none__") && "bg-accent/50"
                  )}
                >
                  <Check
                    className={cn(
                      "h-4 w-4 shrink-0",
                      !value || value === "__none__" ? "opacity-100" : "opacity-0"
                    )}
                  />
                  <span className="text-muted-foreground">
                    {t("community.noRestaurant", "不关联餐厅")}
                  </span>
                </button>
              )}

              {loadAll && isLoading && (
                <div className="px-2 py-6 text-center text-sm text-muted-foreground">
                  {t("common.loading", "加载中...")}
                </div>
              )}

              {!isLoading && filtered.length === 0 && (
                <div className="px-2 py-6 text-center text-sm text-muted-foreground">
                  {t("common.noResults", "无结果")}
                </div>
              )}

              {filtered.map((r) => (
                <button
                  key={r.id}
                  type="button"
                  onClick={() => {
                    onChange(r.id);
                    setOpen(false);
                  }}
                  className={cn(
                    "w-full text-left px-2 py-2 rounded-sm text-sm hover:bg-accent flex items-center gap-2",
                    value === r.id && "bg-accent/50"
                  )}
                >
                  <Check
                    className={cn(
                      "h-4 w-4 shrink-0",
                      value === r.id ? "opacity-100" : "opacity-0"
                    )}
                  />
                  <span className="flex-1 min-w-0 truncate">
                    {getLocalizedField(r, "name")}
                  </span>
                  {r.city && (
                    <span className="text-xs text-muted-foreground shrink-0">
                      {r.city}
                    </span>
                  )}
                </button>
              ))}

              {list.length > filtered.length && query && (
                <div className="px-2 py-2 text-xs text-muted-foreground text-center border-t">
                  {t("community.showingTopResults", "仅显示前 {{n}} 条，请细化搜索", {
                    n: MAX_RESULTS,
                  })}
                </div>
              )}
            </div>
          </ScrollArea>
        </PopoverContent>
      </Popover>
    </div>
  );
};

export default RestaurantPicker;
